require"UI.UIBase"require"UI.UIBlock"UI_ShiMingRenZheng=UIBase:Inherit()function UI_ShiMingRenZheng:OnCreate()UI_ShiMingRenZheng.Inst=self;self.input_name=self.label_name.transform:GetComponent(typeof(UnityEngine.UI.InputField))self.input_id=self.label_id.transform:GetComponent(typeof(UnityEngine.UI.InputField))end;function UI_ShiMingRenZheng:OnShow(a,b)if self.locking then return end;self.locking=true;self.callback=b.callback;self.transform.gameObject:SetActive(true)self:AnimPopOut(self.root.transform,function()a()self.locking=false end)end;function UI_ShiMingRenZheng:OnClose(a)self.locking=true;self:AnimPopHide(self.root.transform,function()self.locking=false;self.transform.gameObject:SetActive(false)if self.callback then self.callback()end;a()end)end;function UI_ShiMingRenZheng.TestDaluId(c)local d='^(([1][1-5])|([2][1-3])|([3][1-7])|([4][1-6])|([5][0-4])|([6][1-5])|([7][1])|([8][1-2]))\\d{4}(([1][9]\\d{2})|([2]\\d{3}))(([0][1-9])|([1][0-2]))(([0][1-9])|([1-2][0-9])|([3][0-1]))\\d{3}[0-9xX]$'if not LuaTools.RegMatch(c,d)then return false end;local e=string.sub(c,7,10)local f=string.sub(c,11,12)local g=string.sub(c,13,14)local h=os.time({year=e,month=f,day=g})local i=Tools.GetRealTime()local j=os.date("%d",os.time({year=e,month=f+1,day=0}))if tonumber(h)>tonumber(i)or tonumber(g)>tonumber(j)then return false end;local k={7,9,10,5,8,4,2,1,6,3,7,9,10,5,8,4,2}local l={'1','0','X','9','8','7','6','5','4','3','2'}local m={}for n=1,Tools.GetStringLength(c)do table.insert(m,string.sub(c,n,n))end;local o=0;for n=1,17 do o=o+tonumber(m[n])*k[n]end;if string.upper(m[18])~=string.upper(l[o%11+1])then return false end;UI_ShiMingRenZheng.Inst.birth_temp=h;return true end;function UI_ShiMingRenZheng.TestDaluPassport(c)local d='^1[45][0-9]{7}|([P|p|S|s]\\d{7})|([S|s|G|g]\\d{8})|([Gg|Tt|Ss|Ll|Qq|Dd|Aa|Ff]\\d{8})|([H|h|M|m]\\d{8，10})$'if not LuaTools.RegMatch(c,d)then return false end;return true end;function UI_ShiMingRenZheng.TestHKId(c)if Tools.GetStringLength(c)~=10 then return false end;if string.sub(c,8,8)~='('and string.sub(c,8,8)~=')'then return false end;if string.sub(c,10,10)~='('and string.sub(c,10,10)~=')'then return false end;local p=0;c=string.upper(c)local q=65;local r=90;local s=48;if not string.match(string.sub(c,1,1),'^[A-Z]$')then return false end;local t=LuaTools.GetCharCode(c,0)p=p+(t-q+1)*8;for n=1,6 do local u=LuaTools.GetCharCode(c,n)local v=u-s;if v<0 or v>9 then return false end;p=p+v*(8-n)end;p=math.fmod(p,11)if p==0 then return string.sub(c,9,9)=='0'elseif p==1 then return string.sub(c,9,9)=='A'else return 11-p==LuaTools.GetCharCode(c,8)-s end end;function UI_ShiMingRenZheng.TestTWId(c)if Tools.GetStringLength(c)~=10 then return false end;c=string.upper(c)local w='ABCDEFGHJKLMNPQRSTUVXYWZIO'local x=-1;local y=true;for n=1,Tools.GetStringLength(w)do if string.sub(w,n,n)==string.sub(c,1,1)and y then x=n-1;y=false end end;if x==-1 then return false end;local z=x+10;local A=math.floor(z/10)local B=math.fmod(z,10)local s=LuaTools.GetCharCode("0",0)local p=A+B*9;for n=1,8 do local v=LuaTools.GetCharCode(c,n)-s;if v<0 or v>9 then return false end;p=p+v*(9-n)end;local C=LuaTools.GetCharCode(c,9)-s;if C<0 or C>9 then return false end;return math.fmod(p,10)==math.fmod(10-C,10)end;function UI_ShiMingRenZheng.TestTaibaoId(c)local D='^\\d{10}\\(B\\)$'local E='^([0-9]{8}|[0-9]{10})$'if not LuaTools.RegMatch(c,D)and not LuaTools.RegMatch(c,E)then return false end;return true end;function UI_ShiMingRenZheng.TestEEPId(c)local d='^[HMhm]{1}([0-9]{10}|[0-9]{8})$'if not LuaTools.RegMatch(c,d)then return false end;return true end;function UI_ShiMingRenZheng.TestEEPTWId(c)local d='^[a-zA-Z][0-9]{9}$'if not LuaTools.RegMatch(c,d)then return false end;return true end;function UI_ShiMingRenZheng.TestAomenId(c)local F="^[1|5|7][0-9]{6}\\([0-9Aa]\\)$"return LuaTools.RegMatch(c,F)end;function UI_ShiMingRenZheng:Confirm()local F='^([\\u4e00-\\u9fa5]){2,10}$'local G=self.input_name.text;G=string.gsub(G,"·","")G=string.gsub(G,'䶮','')if not LuaTools.RegMatch(G,F)then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.Normal,msg=Tools.StrOfLocalization(2181)})return end;local H=self:TestID(self.input_id.text)if H then local I=ProtoMgr.CreateRequest('Lobby','updateIDCardInfo')I.fullname=self.input_name.text;I.card_no=self.input_id.text;LogTool.Info('ShiMingRenZheng','updateIDCardInfo, req: '..pt.block(I))LobbyNetMgr.SendRequest('Lobby','updateIDCardInfo',I,function(J,K)if J or K.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='updateIDCardInfo',error=J,res=K})else GameMgr.Inst.is_authed=true;GameMgr.Inst.account_data.birthday=self.birth_temp end end)self:CloseSelf()else UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.Normal,msg=Tools.StrOfLocalization(2183)})end end;function UI_ShiMingRenZheng:TestID(c)c=Tools.FullWidth2HalfWidth(c)if UI_ShiMingRenZheng.TestDaluId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'dalu')return true end;if UI_ShiMingRenZheng.TestHKId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'hk')return true end;if UI_ShiMingRenZheng.TestTWId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'tw')return true end;if UI_ShiMingRenZheng.TestTaibaoId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'taibao')return true end;if UI_ShiMingRenZheng.TestDaluPassport(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'dalu passport')return true end;if UI_ShiMingRenZheng.TestEEPId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'gangao eep')return true end;if UI_ShiMingRenZheng.TestEEPTWId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'tw eep')return true end;if UI_ShiMingRenZheng.TestAomenId(c)then LogTool.Info('ShiMingRenZheng','证件类型: '..'ao')return true end;LogTool.Info('ShiMingRenZheng','无法识别的证件ID类型')return false end;return UI_ShiMingRenZheng